/* ═══════════════════════════════════════════════
   HELPERS
═══════════════════════════════════════════════ */
const fmt = (n) =>
  "$" + Number(n).toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 2 });

const adminClients = Object.values(CLIENTS)
  .filter((c) => c.role !== "admin")
  .map((c) => ({
    clientName: c.client_name,
    username: c.username,
    mainInvoice: c.main_invoice_number,
    amountDue: fmt(c.dashboard.amount_due),
    paid: fmt(c.dashboard.amount_paid),
    installments: `${c.dashboard.installments_paid} / ${c.dashboard.total_installments}`,
    status: "Active"
  }));

function getOverdue(statements) {
  let count = 0, amount = 0;
  statements.forEach((s) => {
    if (s.status !== "Paid" && new Date(s.due) < TODAY) {
      count++;
      amount += s.amount;
    }
  });
  return { count, amount };
}

function resolveStatus(s) {
  if (s.status === "Paid") return "Paid";
  if (new Date(s.due) < TODAY) return "Overdue";
  return "Pending";
}

function downloadPDF(pdfKey, filename) {
  const b64 = PDF_DATA[pdfKey];
  if (!b64) { alert("PDF not available for this invoice."); return; }
  const bytes = atob(b64);
  const arr = new Uint8Array(bytes.length);
  for (let i = 0; i < bytes.length; i++) arr[i] = bytes.charCodeAt(i);
  const blob = new Blob([arr], { type: "application/pdf" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  a.click();
  setTimeout(() => URL.revokeObjectURL(url), 1000);
}

function initials(name) {
  return name.split(" ").map((w) => w[0]).join("").slice(0, 2).toUpperCase();
}

/* ═══════════════════════════════════════════════
   SHARED UI COMPONENTS
═══════════════════════════════════════════════ */
function StatusBadge({ status }) {
  const cls =
    status === "Paid"
      ? "status-paid"
      : status === "Overdue"
      ? "status-overdue"
      : status === "Active"
      ? "status-paid"
      : "status-pending";

  return <span className={`status-badge ${cls}`}>{status}</span>;
}

function Icon({ src, alt = "", size = 18, className = "" }) {
  return (
    <img
      src={src}
      alt={alt}
      width={size}
      height={size}
      className={className}
      style={{ objectFit: "contain", flexShrink: 0 }}
    />
  );
}

function ActionButton({ kind = "ghost", icon, children, onClick, style }) {
  return (
    <button className={`btn btn-${kind}`} onClick={onClick} style={style}>
      {icon && <Icon src={icon} size={16} />}
      {children}
    </button>
  );
}

function SectionTitle({ title, right }) {
  return (
    <div className="section-header">
      <div className="section-title">{title}</div>
      {right && <div className="section-actions">{right}</div>}
    </div>
  );
}

function StatCard({ color, icon, label, value, sub, progress }) {
  return (
    <div className={`stat-card ${color}`}>
      <div className="stat-icon">
        {typeof icon === "string" && (icon.endsWith(".png") || icon.endsWith(".svg")) ? (
          <Icon src={icon} size={24} />
        ) : (
          icon
        )}
      </div>

      <div className="stat-label">{label}</div>
      <div className="stat-value">{value}</div>

      {sub && <div className="stat-sub">{sub}</div>}

      {progress !== undefined && (
        <div className="progress-bar">
          <div className="progress-fill" style={{ width: `${Math.min(100, progress)}%` }} />
        </div>
      )}
    </div>
  );
}

function InfoRow({ label, value, valueStyle }) {
  return (
    <div className="info-row">
      <span className="info-label">{label}</span>
      <span className="info-value" style={valueStyle}>{value}</span>
    </div>
  );
}

