/*Connect to <Quickbooks*/

function AdminQuickBooksInvoicesPage() {
  const [invoices, setInvoices] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
  async function loadInvoices() {
    try {
      const res = await fetch("https://bosapay-backend.onrender.com/api/qbo/bosapay-invoices");
      const data = await res.json();

      if (!res.ok) {
        throw new Error(data.error || "Failed to load invoices");
      }

      setInvoices(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }

  loadInvoices();
}, []);


  if (loading) return <div className="content">Loading invoices...</div>;
  if (error) return <div className="content">Error: {error}</div>;

  return (
    <div className="content">
      <div className="section-header">
        <div className="section-title">QuickBooks Invoices</div>
      </div>

      <div className="table-wrap">
        <table>
          <thead>
            <tr>
              <th>Invoice #</th>
              <th>Client</th>
              <th>Total</th>
              <th>Paid</th>
              <th>Balance</th>
              <th>Due Date</th>
              <th>Status</th>
            </tr>
          </thead>
          <tbody>
            {invoices.map((inv) => (
              <tr key={inv.id}>
                <td><span className="inv-num">{inv.invoice_number}</span></td>
                <td><strong>{inv.client_name}</strong></td>
                <td>${inv.total_amount.toFixed(2)}</td>
                <td>${inv.amount_paid.toFixed(2)}</td>
                <td>${inv.amount_due.toFixed(2)}</td>
                <td>{inv.due_date || "—"}</td>
                <td><StatusBadge status={inv.status} /></td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════
   LOGIN
═══════════════════════════════════════════════ */
function LoginScreen({ onLogin }) {
  const [user, setUser] = useState("");
  const [pass, setPass] = useState("");
  const [error, setError] = useState(false);

  function attempt() {
    const u = user.trim().toLowerCase();
    const client = CLIENTS[u];

    if (client && client.password === pass) {
      setError(false);
      onLogin(client);
    } else {
      setError(true);
      setPass("");
    }
  }

  const onKey = (e) => {
    if (e.key === "Enter") attempt();
  };

  return (
    <div className="login-screen">
      <div className="login-card">
        <div className="login-logo">
          <img src="/logo-bosapay-azul.png" alt="Bosapay" style={{ maxWidth: 220, width: "100%" }} />
          <div className="logo-sub">Client Portal</div>
        </div>

        <div className="login-title">Welcome back</div>
        <div className="login-subtitle">Sign in to access your account</div>

        <div className="login-field">
          <label className="login-label">Username</label>
          <input
            className="login-input"
            type="text"
            placeholder="Enter your username"
            value={user}
            onChange={(e) => setUser(e.target.value)}
            onKeyDown={onKey}
            autoComplete="username"
          />
        </div>

        <div className="login-field">
          <label className="login-label">Password</label>
          <input
            className="login-input"
            type="password"
            placeholder="Enter your password"
            value={pass}
            onChange={(e) => setPass(e.target.value)}
            onKeyDown={onKey}
            autoComplete="current-password"
          />
        </div>

        <button className="login-btn" onClick={attempt}>Sign In →</button>

        {error && <div className="login-error">Invalid credentials. Please try again.</div>}

        <div className="login-security">Secured by Bosapay · SSL Encrypted</div>
      </div>
    </div>
  );
}

